ee:variables.ee:set-variable:
%dw 2.0
output application/java
---
{
	"query": vars.surveyQuery,
	"inputParameters":{
    ids: {
        value: vars.ids map ($ as Number),
        "type": "ARRAY",
        arrayType: "INTEGER"
    }
},
"user":Mule::p('db.user'),
	"password": Mule::p('secure::db.password'),
	"url":Mule::p('db.assessmenturl')

// "user":"gmmcouat-read-user",
// "password": Mule::p('db.uatpassword'),
// "url":  "jdbc:postgresql://65.2.135.19:5432/glms_assessment?sslmode=require"



}

ee:message.ee:set-payload:
output application/json

var pro = payload
var levelMapping = {
    "1": "Pre-Foundational",
    "2": "Foundational",
    "3": "Advanced",
    "4": "Expert"
}

---
pro map (item) -> {
    (item),
    "SGA Level": levelMapping[item.level_id] default null
}
